// 未优化版本【更直观】
class XorBase {
private:
	vector<ll> a; // 线性基基底
	vector<ll> _3;
	int MN = 38;
public:
	XorBase() :a(40, 0) {
		ll now = 1;
		fa(i, 0, MN) {
			_3.pb(now);
			now *= 3;
		}
	};

	int get_bit3(ll x, ll i) {
		return x / _3[i] % 3;
	}

	ll op(ll x, ll y) {
		ll res = 0;
		fa(i, 0, MN) {
			ll cntx = get_bit3(x, i);
			ll cnty = get_bit3(y, i);
			res += (cntx + cnty) % 3 * _3[i];
		}
		return res;
	}

	void insert(ll x) {
		fb(i, MN, 0) {
			int cnt = get_bit3(x, i);
			if (cnt == 0)continue;
			if (!a[i]) {
				if (cnt == 2)x = op(x, x);
				a[i] = x;
				return;
			}
			else {
				if (cnt == 1)x = op(x, op(a[i], a[i]));
				else x = op(x, a[i]);
			}
		}
	}

	bool check(ll x) {
		fb(i, MN, 0) {
			int cnt = get_bit3(x, i);
			if (cnt == 0)continue;
			if (!a[i])return 0;
			else {
				if (cnt == 1)x = op(x, op(a[i], a[i]));
				else x = op(x, a[i]);
			}
		}
		return 1;
	}
};
void solve(int CASE)
{
	ll n, q; cin >> n >> q;
	var xb = XorBase();
	fa(i, 1, n) {
		ll x; cin >> x;
		xb.insert(x);
	}
	while (q--) {
		ll x; cin >> x;
		if (xb.check(x))cout << "Yes" << endl;
		else cout << "No" << endl;
	}
	return;
}

// 优化除法版本
class XorBase {
private:
	const static int MN = 38;
	array<int, MN + 1> vis;
	vector<array<int, MN + 1>> cnta;
	vector<ll> _3;
public:
	XorBase() :cnta(40) {
		ll now = 1;
		fa(i, 0, MN) {
			_3.pb(now);
			now *= 3;
			fill(all(cnta[i]), 0);
		}
		fill(all(vis), 0);
	};

	int get_bit3(ll x, ll i) {
		return x / _3[i] % 3;
	}

	void insert(ll x) {
		var cnt = array<int, MN + 1>();
		fa(i, 0, MN)cnt[i] = get_bit3(x, i);

		fb(i, MN, 0) {
			if (cnt[i] == 0)continue;
			if (!vis[i]) {
				if (cnt[i] == 2) {
					fa(j, 0, MN)cnt[j] = (cnt[j] * 2) % 3;
				}
				cnta[i] = move(cnt);
				vis[i] = 1;
				return;
			}
			else {
				if (cnt[i] == 1) {
					fa(j, 0, MN)cnt[j] = (cnt[j] + cnta[i][j] + cnta[i][j]) % 3;
				}
				else {
					fa(j, 0, MN)cnt[j] = (cnt[j] + cnta[i][j]) % 3;
				}
			}
		}
	}

	bool check(ll x) {
		var cnt = array<int, MN + 1>();
		fa(i, 0, MN)cnt[i] = get_bit3(x, i);

		fb(i, MN, 0) {
			if (cnt[i] == 0)continue;
			if (!vis[i])return 0;
			else {
				if (cnt[i] == 1) {
					fa(j, 0, MN)cnt[j] = (cnt[j] + cnta[i][j] + cnta[i][j]) % 3;
				}
				else {
					fa(j, 0, MN)cnt[j] = (cnt[j] + cnta[i][j]) % 3;
				}
			}
		}
		return 1;
	}
};
void solve(int CASE)
{
	ll n, q; cin >> n >> q;
	var xb = XorBase();
	fa(i, 1, n) {
		ll x; cin >> x;
		xb.insert(x);
	}
	while (q--) {
		ll x; cin >> x;
		if (xb.check(x))cout << "Yes" << endl;
		else cout << "No" << endl;
	}
	return;
}
